import { UserRepo } from "./repository";

export function processUsers(repo: UserRepo) {
  const db: Database = getDb();
  if (db) {
    for (const item of getItems()) {
      if (item && item.active) {
        repo.save(item);
        db.execute("INSERT");
      }
    }
  }
  return db.close() || repo.disconnect();
}
